#include <bits/stdc++.h>
using namespace std;

int n,s,a,b,ans;
struct apple{
    int x,y;
}f[5005];

bool cmp(apple r,apple w){
    if(r.y==w.y)return r.x<w.x;
    return r.y<w.y;
}

int main(){
    cin>>n>>s;
    cin>>a>>b;
    for(int i=1;i<=n;i++)cin>>f[i].x>>f[i].y;
    sort(f+1,f+n+1,cmp);
    for(int i=1;i<=n && s>0;i++){
        if(f[i].x<=a+b && s>=f[i].y){
            s-=f[i].y;
            ans++;
        }
    }
    cout<<ans;
    return 0;
}
